export type WcTeam = {
  id: number
  name: string
  /** 3-letter FIFA code, e.g. MEX */
  fifaCode: string
  /** ISO 3166-1 alpha-2, lowercase, e.g. mx */
  iso2: string
  /** flagcdn.com image URL */
  flag: string
  /** Group letter A–L */
  group: string
}

export type WcStadium = {
  id: number
  name: string
  fifaName: string
  city: string
  country: string
  capacity: number
  region: string
}

export type WcMatch = {
  id: number
  /** Team id, or 0 for a not-yet-decided knockout slot (see homeLabel). */
  homeTeamId: number
  awayTeamId: number
  /** Placeholder text for undecided knockout slots, e.g. "Winner Match 101". */
  homeLabel: string | null
  awayLabel: string | null
  /** Group letter, or stage label like "R32", "FINAL". */
  group: string
  matchday: number
  /** Naive local kickoff, ISO-ish "YYYY-MM-DDTHH:mm:00". */
  kickoff: string | null
  /** Original source string "MM/DD/YYYY HH:mm". */
  localDate: string
  stadiumId: number
  /** "group" | "round32" | "round16" | ... | "final" */
  type: string
  finished: boolean
  homeScore: number
  awayScore: number
}

