export const wcTeamById = new Map(WC_TEAMS.map((t) => [t.id, t]))
export const wcStadiumById = new Map(WC_STADIUMS.map((s) => [s.id, s]))

export const WC_GROUPS = [...new Set(WC_TEAMS.map((t) => t.group))].sort()

export function wcTeamsInGroup(group: string): WcTeam[] {
  return WC_TEAMS.filter((t) => t.group === group)
}

export function wcGroupMatches(): WcMatch[] {
  return WC_MATCHES.filter((m) => m.type === 'group')
}
